import React, { useEffect, useState } from "react";
import { Table, Button, Input, Modal, Form, Select } from "antd";
import { Trash2, Plus, Pencil, Search, Image as ImageIcon, Upload } from "lucide-react";
import axios from "axios";
import { toast } from "react-toastify";
import { base_url } from "../utils/baseUrl";
import { config } from "../utils/axiosconfig";
import Dropzone from "react-dropzone";

const { TextArea } = Input;

const CareSuggestions = () => {
  const [advices, setAdvices] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [form] = Form.useForm();
  const [searchText, setSearchText] = useState("");
  const [conditionImage, setConditionImage] = useState(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchAdvices();
    fetchProducts();
  }, []);

  const fetchAdvices = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${base_url}health-advice`, config);
      setAdvices(res.data);
    } catch (error) {
      toast.error("Failed to fetch health advices");
    }
    setLoading(false);
  };

  const fetchProducts = async () => {
    try {
      const res = await axios.get(`${base_url}product`, config);
      const prodList = Array.isArray(res.data) ? res.data : (res.data.products || []);
      setProducts(prodList);
    } catch (error) {
      toast.error("Failed to fetch products");
    }
  };

  const showModal = (record = null) => {
    setIsModalOpen(true);
    if (record) {
      setEditingId(record._id);
      setConditionImage(record.image || null);
      form.setFieldsValue({
        conditionName: record.conditionName,
        keySymptoms: record.keySymptoms?.join(", "),
        healthAdvice: record.healthAdvice,
        products: record.products?.map((p) => p._id) || [],
      });
    } else {
      setEditingId(null);
      setConditionImage(null);
      form.resetFields();
    }
  };

  const handleCancel = () => {
    setIsModalOpen(false);
    form.resetFields();
    setEditingId(null);
    setConditionImage(null);
  };

  const handleImageUpload = async (files) => {
    setUploading(true);
    try {
      const formData = new FormData();
      formData.append("multiple_image", files[0]);
      const res = await axios.post(`${base_url}upload/create`, formData, {
        headers: {
          ...config.headers,
          "Content-Type": "multipart/form-data",
        },
      });
      if (res.data?.[0]) {
        setConditionImage({
          public_id: res.data[0].public_id,
          url: res.data[0].secure_url,
        });
        toast.success("Image uploaded successfully");
      }
    } catch (error) {
      toast.error("Image upload failed");
    }
    setUploading(false);
  };

  const handleImageDelete = async () => {
    if (!conditionImage?.public_id) return;
    try {
      await axios.delete(`${base_url}upload/delete-img/${conditionImage.public_id}`, config);
      setConditionImage(null);
      toast.success("Image removed");
    } catch (error) {
      toast.error("Failed to delete image");
    }
  };

  const onFinish = async (values) => {
    const payload = {
      ...values,
      keySymptoms: values.keySymptoms.split(",").map((s) => s.trim()).filter(Boolean),
      image: conditionImage,
    };

    try {
      if (editingId) {
        await axios.put(`${base_url}health-advice/${editingId}`, payload, config);
        toast.success("Health advice updated successfully");
      } else {
        await axios.post(`${base_url}health-advice`, payload, config);
        toast.success("Health advice created successfully");
      }
      setIsModalOpen(false);
      fetchAdvices();
    } catch (error) {
      toast.error("Operation failed");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this advice?")) {
      try {
        await axios.delete(`${base_url}health-advice/${id}`, config);
        toast.success("Deleted successfully");
        fetchAdvices();
      } catch (error) {
        toast.error("Delete failed");
      }
    }
  };

  const columns = [
    {
      title: "Image",
      dataIndex: "image",
      render: (img) => img?.url ? (
        <img src={img.url} alt="condition" className="w-12 h-12 object-cover rounded-lg border border-slate-100" />
      ) : (
        <div className="w-12 h-12 bg-slate-50 flex items-center justify-center rounded-lg border border-slate-100 text-slate-300">
          <ImageIcon size={20} />
        </div>
      ),
    },
    {
      title: "Condition Name",
      dataIndex: "conditionName",
      sorter: (a, b) => a.conditionName.localeCompare(b.conditionName),
      render: (text) => <span className="font-bold text-black">{text}</span>,
    },
    {
      title: "Symptoms",
      dataIndex: "keySymptoms",
      render: (symptoms) => (
        <div className="flex flex-wrap gap-1">
          {symptoms?.map((s, i) => (
            <span key={i} className="bg-blue-50 text-blue-600 px-2 py-0.5 rounded text-xs">
              {s}
            </span>
          ))}
        </div>
      ),
    },
    {
      title: "Advice",
      dataIndex: "healthAdvice",
      width: 300,
      render: (text) => <span className="text-slate-500 line-clamp-2 text-xs">{text}</span>,
    },
    {
      title: "Products Attached",
      dataIndex: "products",
      render: (prods) => (
        <div className="flex flex-col gap-1">
          <span className="font-semibold text-black">{prods?.length || 0} products</span>
          <div className="flex flex-wrap gap-1 max-w-[200px]">
            {prods?.slice(0, 2).map((p, i) => (
              <span key={i} className="text-[10px] bg-slate-100 px-1.5 py-0.5 rounded text-slate-500 truncate max-w-full">
                {p.title}
              </span>
            ))}
            {prods?.length > 2 && <span className="text-[10px] text-slate-400">+{prods.length - 2} more</span>}
          </div>
        </div>
      ),
    },
    {
      title: "Actions",
      key: "actions",
      render: (_, record) => (
        <div className="flex items-center gap-2">
          <Button
            type="text"
            icon={<Pencil size={18} />}
            onClick={() => showModal(record)}
            className="text-slate-400 hover:text-black hover:bg-slate-50 rounded-xl w-10 h-10 flex items-center justify-center transition-all"
          />
          <Button
            type="text"
            icon={<Trash2 size={18} />}
            onClick={() => handleDelete(record._id)}
            className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl w-10 h-10 flex items-center justify-center transition-all"
          />
        </div>
      ),
    },
  ];

  const filteredData = advices.filter(
    (a) =>
      !searchText ||
      a.conditionName?.toLowerCase().includes(searchText.toLowerCase()) ||
      a.keySymptoms?.some((s) => s.toLowerCase().includes(searchText.toLowerCase()))
  );

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-[28px] font-bold text-black">Care Suggestions</h1>
          <p className="text-[15px] text-slate-500 mt-1">
            Manage disease symptoms, indicators, and pharmacist-verified suggestions.
          </p>
        </div>
        <Button
          type="primary"
          onClick={() => showModal()}
          className="rounded-xl h-11 bg-[#1e3a8a] text-white font-bold text-[14px] shadow-sm px-6 border-none flex items-center gap-2"
        >
          <Plus size={18} /> Add Suggestion
        </Button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center p-6 border-b border-slate-50 gap-4">
          <div className="flex items-center gap-2">
            <span className="text-[15px] font-bold text-black">Active Suggestions:</span>
            <span className="bg-slate-100 text-slate-700 px-3 py-0.5 rounded-lg text-[14px] font-bold">
              {filteredData.length}
            </span>
          </div>
          <div className="relative w-full sm:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input
              type="text"
              placeholder="Search conditions or symptoms..."
              className="pl-10 pr-4 h-11 w-full bg-slate-50/50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 text-[14px] font-medium"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={filteredData}
          rowKey="_id"
          loading={loading}
          pagination={{ pageSize: 15, className: "px-6 py-4" }}
          className="modern-table text-xs"
        />
      </div>

      <Modal
        title={editingId ? "Edit Care Suggestion" : "Add Care Suggestion"}
        open={isModalOpen}
        onCancel={handleCancel}
        footer={null}
        width={720}
      >
        <Form form={form} layout="vertical" onFinish={onFinish} className="mt-4 grid grid-cols-2 gap-4">
          <div className="col-span-2 sm:col-span-1">
             <Form.Item
                name="conditionName"
                label="Condition Name"
                rules={[{ required: true, message: "Required" }]}
              >
                <Input placeholder="e.g. Common Cold" size="large" />
              </Form.Item>

              <Form.Item
                name="keySymptoms"
                label="Key Symptoms (comma separated)"
                rules={[{ required: true, message: "Required" }]}
              >
                <Input placeholder="e.g. runny nose, cough" size="large" />
              </Form.Item>
          </div>

          <div className="col-span-2 sm:col-span-1">
              <label className="text-[14px] font-medium mb-2 block">Disease Indicator Image</label>
              <div className="h-[120px] mb-4">
                {conditionImage ? (
                  <div className="relative h-full w-full rounded-xl overflow-hidden border border-slate-200 group">
                    <img src={conditionImage.url} className="w-full h-full object-cover" alt="Condition" />
                    <button 
                      type="button"
                      onClick={handleImageDelete}
                      className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity text-white"
                    >
                      <Trash2 size={24} />
                    </button>
                  </div>
                ) : (
                  <Dropzone onDrop={handleImageUpload} multiple={false} accept={{"image/*": []}}>
                    {({getRootProps, getInputProps}) => (
                      <div {...getRootProps()} className="border-2 border-dashed border-slate-200 rounded-xl h-full flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/30 transition-all">
                        <input {...getInputProps()} />
                        <Upload size={24} className="text-slate-400 mb-2" />
                        <span className="text-xs text-slate-500 font-medium">Click to upload indicator image</span>
                      </div>
                    )}
                  </Dropzone>
                )}
              </div>
          </div>

          <Form.Item
            name="healthAdvice"
            label="Pharmacist Verified Analysis & Advice"
            rules={[{ required: true, message: "Required" }]}
            className="col-span-2"
          >
            <TextArea rows={6} placeholder="Detailed analysis and lifestyle recommendations..." size="large" />
          </Form.Item>

          <Form.Item name="products" label="Manufacturer Suggested Products (Available OTC)" className="col-span-2">
            <Select
              mode="multiple"
              allowClear
              placeholder="Search and select real inventory products"
              size="large"
              options={products.map((p) => ({ 
                  label: (
                      <div className="flex items-center gap-2">
                        <img src={(Array.isArray(p.colors?.[0]?.images) ? p.colors?.[0]?.images?.[0]?.secure_url : p.colors?.[0]?.images?.secure_url)} className="w-6 h-6 rounded object-cover" />
                        <span>{p.title}</span>
                      </div>
                  ), 
                  value: p._id 
              }))}
              filterOption={(input, option) =>
                (option?.label.props.children[1].props.children ?? "").toLowerCase().includes(input.toLowerCase())
              }
            />
          </Form.Item>

          <div className="col-span-2 flex justify-end gap-3 mt-6">
            <Button onClick={handleCancel} size="large" className="rounded-xl">
              Cancel
            </Button>
            <Button type="primary" htmlType="submit" size="large" className="bg-[#1e3a8a] rounded-xl px-8" loading={uploading}>
              {editingId ? "Update" : "Save"} Guide
            </Button>
          </div>
        </Form>
      </Modal>

      <style>{`
        .modern-table .ant-table-thead > tr > th {
          background: #fff !important;
          font-weight: 700 !important;
          font-size: 11px !important;
          color: #94a3b8 !important;
          text-transform: uppercase !important;
          letter-spacing: 0.1em !important;
          border-bottom: 2px solid #f1f5f9 !important;
          padding: 16px 24px !important;
        }
        .modern-table .ant-table-tbody > tr > td {
          padding: 16px 24px !important;
          border-bottom: 1px solid #f8fafc !important;
        }
      `}</style>
    </div>
  );
};

export default CareSuggestions;
